export function getAspectContent(planet1: string, planet2: string, aspectType: string): AspectContent | null {
  const key = `aspect:${planet1.toLowerCase()}:${planet2.toLowerCase()}:${aspectType.toLowerCase()}`;
  const reverseKey = `aspect:${planet2.toLowerCase()}:${planet1.toLowerCase()}:${aspectType.toLowerCase()}`;
  return ASPECTS[key] ?? ASPECTS[reverseKey] ?? null;
}
